struct DfsContext {
    timer: usize,
    dfn: Vec<usize>,
    low: Vec<usize>,
    is_ap: Vec<bool>,
}

impl DfsContext {
    fn new(n: usize) -> Self {
        DfsContext {
            timer: 0,
            dfn: vec![0; n],
            low: vec![0; n],
            is_ap: vec![false; n],
        }
    }
}

fn dfs(u: usize, p: isize, adj: &Vec<Vec<usize>>, ctx: &mut DfsContext) {
    ctx.timer += 1;
    ctx.dfn[u] = ctx.timer;
    ctx.low[u] = ctx.timer;
    let mut children = 0;

    for &v in &adj[u] {
        if v as isize == p {
            continue;
        }
        if ctx.dfn[v] != 0 {
            ctx.low[u] = min(ctx.low[u], ctx.dfn[v]);
        } else {
            children += 1;
            dfs(v, u as isize, adj, ctx);
            ctx.low[u] = min(ctx.low[u], ctx.low[v]);
            if p != -1 && ctx.low[v] >= ctx.dfn[u] {
                ctx.is_ap[u] = true;
            }
        }
    }

    if p == -1 && children > 1 {
        ctx.is_ap[u] = true;
    }
}

