export function articulationPoints(arr: number[]): number {
  if (arr.length < 2) return 0;
  const n = arr[0];
  const m = arr[1];

  if (arr.length < 2 + 2 * m) return 0;

  const adj: number[][] = Array.from({ length: n }, () => []);
  for (let i = 0; i < m; i++) {
    const u = arr[2 + 2 * i];
    const v = arr[2 + 2 * i + 1];
    if (u >= 0 && u < n && v >= 0 && v < n) {
      adj[u].push(v);
      adj[v].push(u);
    }
  }

  const dfn: number[] = new Array(n).fill(0);
  const low: number[] = new Array(n).fill(0);
  const isAp: boolean[] = new Array(n).fill(false);
  let timer = 0;

  function dfs(u: number, p: number): void {
    timer++;
    dfn[u] = low[u] = timer;
    let children = 0;

    for (const v of adj[u]) {
      if (v === p) continue;
      if (dfn[v] !== 0) {
        low[u] = Math.min(low[u], dfn[v]);
      } else {
        children++;
        dfs(v, u);
        low[u] = Math.min(low[u], low[v]);
        if (p !== -1 && low[v] >= dfn[u]) {
          isAp[u] = true;
        }
      }
    }

    if (p === -1 && children > 1) {
      isAp[u] = true;
    }
  }

  for (let i = 0; i < n; i++) {
    if (dfn[i] === 0) dfs(i, -1);
  }

  return isAp.filter(x => x).length;
}

export function articulationPoints(arr: number[]): number {
    const n = arr[0];
    const m = arr[1];
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) {
        const u = arr[2 + 2 * i];
        const v = arr[2 + 2 * i + 1];
        adj[u].push(v);
        adj[v].push(u);
    }

    const disc = new Array(n).fill(-1);
    const low = new Array(n).fill(0);
    const parent = new Array(n).fill(-1);
    const isAp = new Array(n).fill(false);
    let timer = 0;

    function dfs(u: number): void {
        disc[u] = timer;
        low[u] = timer;
        timer++;
        let children = 0;

        for (const v of adj[u]) {
            if (disc[v] === -1) {
                children++;
                parent[v] = u;
                dfs(v);
                low[u] = Math.min(low[u], low[v]);
                if (parent[u] === -1 && children > 1) isAp[u] = true;
                if (parent[u] !== -1 && low[v] >= disc[u]) isAp[u] = true;
            } else if (v !== parent[u]) {
                low[u] = Math.min(low[u], disc[v]);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        if (disc[i] === -1) dfs(i);
    }

    return isAp.filter(x => x).length;
}
